using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();

            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateSeeded(string dbName = null)
        {
            var context = Create(dbName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var students = new[]
            {
                new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2019, 9, 1) },
                new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2017, 9, 1) },
                new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2018, 9, 1) },
                new Student { ID = 4, FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = new DateTime(2017, 9, 1) },
            };
            context.Students.AddRange(students);

            var instructors = new[]
            {
                new Instructor { ID = 10, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6), CourseAssignments = new List<CourseAssignment>() },
            };
            context.Instructors.AddRange(instructors);

            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = 10 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1), InstructorID = 11 },
            };
            context.Departments.AddRange(departments);

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1, CourseAssignments = new List<CourseAssignment>(), Enrollments = new List<Enrollment>() },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2, CourseAssignments = new List<CourseAssignment>(), Enrollments = new List<Enrollment>() },
                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2, CourseAssignments = new List<CourseAssignment>(), Enrollments = new List<Enrollment>() },
            };
            context.Courses.AddRange(courses);

            context.CourseAssignments.AddRange(
                new CourseAssignment { CourseID = 1050, InstructorID = 10 },
                new CourseAssignment { CourseID = 4022, InstructorID = 11 }
            );

            context.Enrollments.AddRange(
                new Enrollment { StudentID = 1, CourseID = 1050, Grade = Grade.A },
                new Enrollment { StudentID = 2, CourseID = 4022, Grade = Grade.C },
                new Enrollment { StudentID = 1, CourseID = 4022, Grade = Grade.B }
            );

            context.OfficeAssignments.Add(
                new OfficeAssignment { InstructorID = 10, Location = "Smith 17" }
            );

            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Models;
