using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue after each test
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.Contains("Chemistry", notification.Message);
            Assert.Contains("Course", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            _service.SendNotification("Department", "5", "English", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.Contains("deleted", notification.Message);
            Assert.Contains("English", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultsToSystemUser()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();

            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFO()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_WithInvalidId_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(-1));
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName()
        {
            _service.SendNotification("Instructor", "7", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("7", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_CreateMessage_Format()
        {
            _service.SendNotification("Course", "1", "Physics", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Course 'Physics' has been created", n.Message);
        }

        [Fact]
        public void SendNotification_UpdateMessage_Format()
        {
            _service.SendNotification("Course", "1", "Physics", EntityOperation.UPDATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Physics' has been updated", n.Message);
        }

        [Fact]
        public void SendNotification_DeleteMessage_Format()
        {
            _service.SendNotification("Course", "1", "Physics", EntityOperation.DELETE);
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Physics' has been deleted", n.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_CreateMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var n = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 42) has been created", n.Message);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void MultipleNotifications_AllEnqueued()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var notifications = new List<Notification>();
            Notification n;
            while ((n = _service.ReceiveNotification()) != null)
            {
                notifications.Add(n);
            }

            Assert.Equal(5, notifications.Count);
        }
    }
}

