        public void Index_NullSearch_UsesCurrentFilter()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
