using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentData()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new HomeController(context);

            var result = controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new HomeController(context);

            var result = controller.About();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);

            // We seeded 4 students with 3 distinct dates (2017 has 2 students)
            var totalStudents = model.Sum(g => g.StudentCount);
            Assert.Equal(4, totalStudents);
        }

        [Fact]
        public void Contact_SetsViewBagMessage()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Contact();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsView()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_SetsViewBagMessage()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Unauthorized();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

