using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Linq;
using System.Net;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private StudentsController CreateController(SchoolContext context)
        {
            var controller = new StudentsController(context);
            controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
            return controller;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithStudents()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(4, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Barzdukas", model.First().LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByDateAscending()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            // 2017 dates should come first
            Assert.Equal(2017, model.First().EnrollmentDate.Year);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByDateDescending()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(2019, model.First().EnrollmentDate.Year);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SearchResetsPage()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, null, "newSearch", 3);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearch_UsesCurrentFilter()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParms()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            controller.Index(null, null, null, null);

            Assert.Equal("name_desc", controller.ViewBag.NameSortParm);
            Assert.Equal("Date", controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_NameDescSort_SetsNameSortParmToEmpty()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            controller.Index("name_desc", null, null, null);

            Assert.Equal("", controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_DateSort_SetsDateSortParmToDateDesc()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", controller.ViewBag.DateSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudent()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Details_IncludesEnrollments()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Equal(2, model.Enrollments.Count);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            using var context = TestDbContextFactory.Create();
            var controller = CreateController(context);

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
