using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using System.Net;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _tempDir = Path.Combine(Path.GetTempPath(), $"contoso_test_{Guid.NewGuid()}");
            Directory.CreateDirectory(_tempDir);
        }

        public void Dispose()
        {
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, true);
        }

        private CoursesController CreateController(SchoolContext context)
        {
            var envMock = new Mock<IWebHostEnvironment>();
            envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
            var loggerMock = new Mock<ILogger<CoursesController>>();
            return new CoursesController(context, envMock.Object, loggerMock.Object);
        }

        private IFormFile CreateMockFile(string fileName, long length = 1024)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mock.Object;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Details_IncludesDepartment()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.NotNull(model.Department);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentList()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Get_ReturnsNewCourse()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = controller.Create(course, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_SavesInDatabase()
        {
            using var context = TestDbContextFactory.CreateSeeded();
