            var course = new Course { CourseID = 9999, DepartmentID = 1 };

            var result = controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
