using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;
using System.Net;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsDepartment()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorList()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Create();

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 10
            };

            var result = controller.Create(dept);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesInDatabase()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1)
            };

            controller.Create(dept);

            Assert.Equal(3, context.Departments.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = controller.Create(dept);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsDepartment()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);
            var dept = context.Departments.Find(1);
            context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 10
            };

            var result = controller.Edit(updated);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { DepartmentID = 1, InstructorID = 10 };

            var result = controller.Edit(dept);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsDepartment()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal("English", model.Name);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesDepartment()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            controller.DeleteConfirmed(1);

            Assert.Null(context.Departments.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new DepartmentsController(context);

            var result = controller.DeleteConfirmed(1);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        #endregion
    }
}

