using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        #region Index

        [Fact]
        public void Index_ReturnsViewWithInstructors()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_OrdersInstructorsByLastName()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Equal("Abercrombie", model.Instructors.First().LastName);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Index(10, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses); // Instructor 10 has 1 course (1050)
        }

        [Fact]
        public void Index_WithInstructorId_SetsViewBagInstructorID()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            controller.Index(10, null);

            Assert.Equal(10, controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Index(10, 1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_WithCourseId_SetsViewBagCourseID()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            controller.Index(10, 1050);

            Assert.Equal(1050, controller.ViewBag.CourseID);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Details(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        [Fact]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            controller.Create();

            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(3, courses.Count);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new System.DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new System.DateTime(2020, 1, 1)
            };

            controller.Create(instructor, new[] { "1050", "4022" });

            var saved = context.Instructors.Where(i => i.LastName == "Instructor").Single();
            var assignments = context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = new System.DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Edit(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        [Fact]
        public void Edit_Get_PopulatesAssignedCourseData()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            controller.Edit(10);

            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            // 1050 assigned to instructor 10
            Assert.Contains(courses, c => c.CourseID == 1050 && c.Assigned);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.Delete(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            controller.DeleteConfirmed(10);

            Assert.Null(context.Instructors.Find(10));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);

            var result = controller.DeleteConfirmed(10);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new InstructorsController(context);
            // Instructor 10 is admin of department 1

            controller.DeleteConfirmed(10);

            var dept = context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }

        #endregion
    }
}

