using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests
    {
        [Fact]
        public void Index_ReturnsView()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsJson()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsSuccessTrue()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsJson()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_WithInvalidId_DoesNotThrow()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var exception = Record.Exception(() => controller.MarkAsRead(-1));
            Assert.Null(exception);
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            using var context = TestDbContextFactory.Create();
            var service = new NotificationService();
            // Drain queue first
            while (service.ReceiveNotification() != null) { }

            // Enqueue 15 notifications
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var controller = new NotificationsController(context);
            var result = controller.GetNotifications();

            // The controller drains up to 10 from the shared queue
            Assert.IsType<JsonResult>(result);

            // Drain remaining
            while (service.ReceiveNotification() != null) { }
        }
    }
}

